export function showNode(id, options = {}) {
  const { expand = true, select = true, focus = true } = options;

  for (const child of nodes) {
    const path = findNodeById(child, id);

    if (path) {
      const ids = path.map((node) => node.id);
      const lastId = ids[ids.length - 1];

      if (expand) {
        const ancestorIds = ids.slice(0, -1);
        for (const ancestorId of ancestorIds) {
          expandedIdsSet.add(ancestorId);
        }
        expandedIds = Array.from(expandedIdsSet);
        lastExpandedIdsRef = expandedIds;
      }

      if (select) {
        activeId = lastId;
        const targetNode = path[path.length - 1];
        if (multiselect && multiselectMode !== "node") {
          selectedIds = multiselectExpansionIds(targetNode, multiselectMode);
        } else {
          selectedIds = [lastId];
        }
      }

      if (focus) {
        tick().then(() => {
          ref?.querySelector(`[id="${CSS.escape(lastId)}"]`)?.focus();
        });
      }

      break;
    }
  }
}

function renderPropsSection(
  component: ComponentApiEntry,
  componentName: string,
) {
  const props = Array.isArray(component.props) ? component.props : [];
  if (props.length === 0) return "";

  const sorted = [...props].sort((a, b) => {
    if (a.isRequired !== b.isRequired) return b.isRequired ? 1 : -1;
    if (a.reactive !== b.reactive) return b.reactive ? 1 : -1;
    return 0;
  });

  const rows = sorted.map((prop) => {
    const markers = [
      prop.reactive ? "Reactive" : null,
      prop.isRequired ? "Required" : null,
    ].filter(Boolean);

    const nameCell = [
      `\`${prop.name}\``,
      markers.length ? `(${markers.join(", ")})` : "",
    ]
      .filter(Boolean)
      .join(" ");

    const { mainDescription } = parseDescription(prop.description ?? "");

    const typeCell = prop.type ? `\`${prop.type}\`` : "";

    const value = prop.value;
    const defaultCell =
      value === undefined || value === "undefined"
        ? "_undefined_"
        : `\`${String(value)}\``;

    return [nameCell, typeCell, mainDescription, defaultCell];
  });

  return `### \`${componentName}\` props\n\n${renderMarkdownTable(
    ["Prop", "Type", "Description", "Default"],
    rows,
  )}`;
}

function inlineFileSources(body: string) {
  const lines = body.split("\n");
  const out: string[] = [];

  let inFence = false;
  const isFence = (line: string) => line.trimStart().startsWith("```");

  for (const line of lines) {
    if (isFence(line)) {
      inFence = !inFence;
      out.push(line);
      continue;
    }

    const trimmed = line.trimStart();
    if (
      inFence ||
      !FILE_SOURCE_START_RE.test(trimmed) ||
      !trimmed.includes("src=") ||
      !trimmed.includes("/>")
    ) {
      out.push(line);
      continue;
    }

    const srcMatch = line.match(FILE_SOURCE_SRC_ATTR_RE);
    const src = srcMatch?.[1];
    if (!src) {
      out.push(line);
      continue;
    }

    const rel = src.startsWith("/") ? src.slice(1) : src;
    const filePath = path.join("src/pages", `${rel}.svelte`);

    try {
      const source = fs.readFileSync(filePath, "utf8");
      out.push("```svelte");
      out.push(source.trimEnd());
      out.push("```");
      out.push("");
    } catch {
      out.push(line);
    }
  }

  return out.join("\n");
}

function sort() {
  const selectedIdsSet = new Set(selectedIds);

  const selectAllEntries = items
    .filter((item) => item.isSelectAll)
    .map((item) => {
      const regularItems = items.filter((i) => !i.isSelectAll && !i.disabled);
      const allChecked =
        regularItems.length > 0 &&
        regularItems.every((i) => selectedIdsSet.has(i.id));
      return { ...item, checked: allChecked };
    });

  const regularItems = items.filter((item) => !item.isSelectAll);

  if (
    selectionFeedback === "top" ||
    selectionFeedback === "top-after-reopen"
  ) {
    const checkedItems = regularItems
      .filter((item) => selectedIdsSet.has(item.id))
      .map((item) => ({ ...item, checked: true }));
    const uncheckedItems = regularItems
      .filter((item) => !selectedIdsSet.has(item.id))
      .map((item) => ({ ...item, checked: false }));

    return [
      ...selectAllEntries,
      ...(checkedItems.length > 1
        ? checkedItems.sort(sortItem)
        : checkedItems),
      ...uncheckedItems.sort(sortItem),
    ];
  }

  return [
    ...selectAllEntries,
    ...regularItems
      .map((item) => ({
        ...item,
        checked: selectedIdsSet.has(item.id),
      }))
      .sort(sortItem),
  ];
}

