    currentIndex.set(0);
  }

  onMountAfterUpdate = false;
}

function handleGpuCountChange(event: Event) {
	const target = event.target as HTMLInputElement;
	let inputValue = target.value;
	const previousValue = gpuCount.toString();

	// Remove any non-numeric characters
	let cleanedValue = inputValue.replace(/[^0-9]/g, "");

	// Prevent deletion of a single digit
	if (cleanedValue === "" && previousValue.length === 1) {
		target.value = previousValue;
		return;
	}

	// Handle input cases
	if (cleanedValue !== "") {
		const numValue = parseInt(cleanedValue, 10);

		// If we already have 2 digits and user is trying to type more, keep the original value
		if (
			previousValue.length === 2 &&
			cleanedValue !== previousValue &&
			cleanedValue.length === 3
		) {
			target.value = previousValue;
			return;
		}

		// Ensure value is within valid range (1-99)
		if (numValue < 1) {
			cleanedValue = "1";
		} else if (numValue > 99) {
			cleanedValue = "99";
		}

		// Update both the input value and the state
		target.value = cleanedValue;
		gpuCount = parseInt(cleanedValue, 10);
	}
}

async function getFileDependencies(
	filename: string,
	content: string
): Promise<{ registryDependencies: Set<string> }> {
	let ast: unknown;
	let moduleAst: unknown;

	if (filename.endsWith(".svelte")) {
		const { code } = await svelte.preprocess(content, [], { filename });
		const result = svelte.parse(code, { filename });
		ast = result.instance;
		if (result.module) {
			moduleAst = result.module;
		}
	} else {
		ast = tsParser.parse(content, { ecmaVersion: "latest", sourceType: "module" });
	}

	const registryDependencies = new Set<string>();

	const enter = (node: Node) => {
		if (node.type === "ImportDeclaration") {
			const source = node.source.value as string;

			if (source.startsWith(REGISTRY_DEPENDENCY) && source !== UTILS_PATH) {
				if (source.includes("ui")) {
					const component = source.split("/").at(-2)!;
					registryDependencies.add(component);
				} else if (source.includes("hook")) {
					const hook = source.split("/").at(-1)!.split(".")[0];
					registryDependencies.add(hook);
				}
			}
		}
	};

	// @ts-expect-error yea, stfu
	walk(ast, { enter });

	if (moduleAst) {
		// @ts-expect-error yea, stfu x2
		walk(moduleAst, { enter });
	}

	return { registryDependencies };
}

export function getThemeCode(theme: BaseColor | undefined, radius: number) {
	if (!theme) {
		return "";
	}

	const replaceTemplate = (
		str: string,
		obj: Record<
			string,
			Record<string, Record<string, string>> | Record<string, string> | string
		>
	) => {
		let result = str;
		for (const key in obj) {
			const pattern = new RegExp(`<%- ${key}\\[["']([^"']+)["']\\] %>`, "g");
			result = result.replace(pattern, (_: string, k: string) => {
				const value = obj[key];
				if (
					typeof value === "object" &&
					typeof (value as Record<string, string | Record<string, string>>)[k] ===
						"string"
				) {
					return (
						((value as Record<string, string | Record<string, string>>)[
							k
						] as string) ?? ""
					);
				}
				return "";
			});
			const simplePattern = new RegExp(`<%- ${key} %>`, "g");
			result = result.replace(simplePattern, String(obj[key]));
		}
		return result;
	};

	return replaceTemplate(BASE_STYLES_WITH_VARIABLES, {
		colors: theme.cssVars,
		radius: radius.toString(),
	});
}

function handleKeyDown(e: KeyboardEvent) {
	// randomize / reset on r/R and shift+R
	if ((e.key === "r" || e.key === "R") && !e.metaKey && !e.ctrlKey) {
		if (
			(e.target instanceof HTMLElement && e.target.isContentEditable) ||
			e.target instanceof HTMLInputElement ||
			e.target instanceof HTMLTextAreaElement ||
			e.target instanceof HTMLSelectElement
		) {
			return;
		}

		e.preventDefault();

		if (e.shiftKey) {
			designSystem.reset();
			return;
		}

		designSystem.randomize();
	}

	// toggle theme on d/D
	if ((e.key === "d" || e.key === "D") && !e.metaKey && !e.ctrlKey) {
		if (
			(e.target instanceof HTMLElement && e.target.isContentEditable) ||
			e.target instanceof HTMLInputElement ||
			e.target instanceof HTMLTextAreaElement ||
			e.target instanceof HTMLSelectElement
		) {
			return;
		}

		e.preventDefault();
		toggleMode();
	}

	// undo/redo on z/Z
	if ((e.key === "z" || e.key === "Z") && (e.metaKey || e.ctrlKey)) {
		e.preventDefault();
		if (e.shiftKey) {
			designSystem.redo();
		} else {
			designSystem.undo();
		}
	}
}

export function createFileTreeForRegistryItemFiles(
	files: Array<{ target: string; type: RegistryItemFile["type"] }> | undefined
): FileTree[] {
	if (!files || !Array.isArray(files)) {
		return [];
	}

	const root: FileTree[] = [];

	for (const file of files) {
		const path = file.target;
		const parts = path.split("/");
		let currentLevel = root;

		for (let i = 0; i < parts.length; i++) {
			const part = parts[i];
			const isFile = i === parts.length - 1;
			const existingNode = currentLevel.find((node) => node.name === part);

			if (existingNode) {
				if (isFile) {
					existingNode.path = path;
				} else {
					currentLevel = existingNode.children!;
				}
			} else {
				const newNode: FileTree = isFile
					? { name: part, path }
					: { name: part, children: [] };

				currentLevel.push(newNode);

				if (!isFile) {
					currentLevel = newNode.children!;
				}
			}
		}
	}

	return root;
}

export function processMeltAttributes(input) {
	let output = input;
	let meltAttribute = extractMeltAttribute(output);

	let tries = 0;
	while (meltAttribute !== null && tries < 100000) {
		tries++;
		const { builder } = meltAttribute;
		const store = builder.startsWith('$') ? builder.slice(1) : builder;

		let /** @type {string} */ oldMelt, /** @type {string} */ newMelt;
		if ('args' in meltAttribute) {
			const { args } = meltAttribute;
			oldMelt = `use:melt={${builder}(${args})}`;
			newMelt = `{...${builder}(${args})} use:${store}`;
		} else if ('index' in meltAttribute) {
			const { index } = meltAttribute;
			oldMelt = `use:melt={${builder}[${index}]}`;
			newMelt = `{...${builder}[${index}]} use:${store}`;
		} else if (builder.startsWith('$')) {
			oldMelt = `use:melt={${builder}}`;
			newMelt = `{...${builder}} use:${store}`;
		} else {
			oldMelt = `use:melt={${builder}}`;
			newMelt = `{...${builder}} use:${builder}.action`;
		}

		output = output.replace(oldMelt, newMelt);
		meltAttribute = extractMeltAttribute(output);
	}
	if (tries >= 100000) throw new Error('Too many tries');

	return output;
}

function <
	S extends
		| WithGet<Readable<unknown>>
		| [WithGet<Readable<unknown>>, ...Array<WithGet<Readable<unknown>>>]
		| Array<WithGet<Readable<unknown>>>,
	T
>(stores: S, fn: (values: StoresValues<S>) => T): WithGet<Readable<T>> {
	const subscribers: Map<(value: T) => void, Array<() => void>> = new Map();

	const get = () => {
		const values = Array.isArray(stores) ? stores.map((store) => store.get()) : stores.get();

		return fn(values as StoresValues<S>);
	};

	const subscribe = (subscriber: (value: T) => void) => {
		const unsubscribers: Array<() => void> = [];
		const storesArr = Array.isArray(stores) ? stores : [stores];
		storesArr.forEach((store) => {
			unsubscribers.push(
				store.subscribe(() => {
					subscriber(get());
				})
			);
		});

		subscriber(get());

		subscribers.set(subscriber, unsubscribers);

		return () => {
			const unsubscribers = subscribers.get(subscriber);
			if (unsubscribers) {
				for (const unsubscribe of unsubscribers) {
					unsubscribe();
				}
			}
			subscribers.delete(subscriber);
		};
	};

	return {
		get,
		subscribe,
	};
}

export function createSync<Stores extends Record<string, Writable<unknown>>>(stores: Stores) {
	let setters = {} as {
		[K in keyof Stores]?: (value: WritableValue<Stores[K]>) => void;
	};
	keys(stores).forEach((key) => {
		const store = stores[key];
		effect(store, (value) => {
			if (key in setters) {
				// eslint-disable-next-line @typescript-eslint/no-explicit-any
				setters[key]?.(value as any);
			}
		});
	});

	return keys(stores).reduce(
		(acc, key) => {
			type Value = WritableValue<Stores[typeof key]>;
			return {
				...acc,
				[key]: function sync(value: Value, setter?: (value: Value) => void) {
					stores[key].update((p) => {
						if (dequal(p, value)) return p;
						return value;
					});
					if (setter) {
						setters = { ...setters, [key]: setter };
					}
				},
			};
		},
		{} as {
			[K in keyof Stores]: (
				value: WritableValue<Stores[K]>,
				setter?: (value: WritableValue<Stores[K]>) => void
			) => void;
		}
	);
}

create(context) {
	const filename = context.filename;

	// Only apply this rule to files in packages/kit/src/runtime
	const in_runtime = filename.includes(path.join('packages', 'kit', 'src', 'runtime'));

	if (!in_runtime) {
		return {};
	}

	return {
		ImportDeclaration(node) {
			const import_path = node.source.value;

			// Check if this is a relative import
			if (typeof import_path === 'string' && import_path.startsWith('.')) {
				// Resolve the import path relative to the current file
				const current_dir = path.dirname(filename);
				const resolved_path = path.resolve(current_dir, import_path);

				// Check if the resolved path points to src/exports
				const exports_path = path.join('packages', 'kit', 'src', 'exports');

				if (resolved_path.includes(exports_path)) {
					context.report({
						node: node.source,
						messageId: 'noRuntimeToExportsImport'
					});
				}
			}
		}
	};
}

export function normalizeUrl(url) {
	url = new URL(url, 'a://a');

	const is_route_resolution = has_resolution_suffix(url.pathname);
	const is_data_request = has_data_suffix(url.pathname);
	const has_trailing_slash = url.pathname !== '/' && url.pathname.endsWith('/');

	if (is_route_resolution) {
		url.pathname = strip_resolution_suffix(url.pathname);
	} else if (is_data_request) {
		url.pathname = strip_data_suffix(url.pathname);
	} else if (has_trailing_slash) {
		url.pathname = url.pathname.slice(0, -1);
	}

	return {
		url,
		wasNormalized: is_data_request || is_route_resolution || has_trailing_slash,
		denormalize: (new_url = url) => {
			new_url = new URL(new_url, url);
			if (is_route_resolution) {
				new_url.pathname = add_resolution_suffix(new_url.pathname);
			} else if (is_data_request) {
				new_url.pathname = add_data_suffix(new_url.pathname);
			} else if (has_trailing_slash && !new_url.pathname.endsWith('/')) {
				new_url.pathname += '/';
			}
			return new_url;
		}
	};
}

function derive_remote_function_event(event, state, allow_cookies) {
	return {
		event: {
			...event,
			setHeaders: () => {
				throw new Error('setHeaders is not allowed in remote functions');
			},
			cookies: {
				...event.cookies,
				set: (name, value, opts) => {
					if (!allow_cookies) {
						throw new Error('Cannot set cookies in `query` or `prerender` functions');
					}

					if (opts.path && !opts.path.startsWith('/')) {
						throw new Error('Cookies set in remote functions must have an absolute path');
					}

					return event.cookies.set(name, value, opts);
				},
				delete: (name, opts) => {
					if (!allow_cookies) {
						throw new Error('Cannot delete cookies in `query` or `prerender` functions');
					}

					if (opts.path && !opts.path.startsWith('/')) {
						throw new Error('Cookies deleted in remote functions must have an absolute path');
					}

					return event.cookies.delete(name, opts);
				}
			}
		},
		state: {
			...state,
			is_in_remote_function: true
		}
	};
}

private updateDocInfo() {
    this.html = parseHtml(this.content);
    const update = (config: SvelteConfig | undefined) => {
        const scriptTags = extractScriptTags(this.content, this.html);
        this.config = config;
        this.scriptInfo = this.addDefaultLanguage(config, scriptTags?.script || null, 'script');
        this.moduleScriptInfo = this.addDefaultLanguage(
            config,
            scriptTags?.moduleScript || null,
            'script'
        );
        this.styleInfo = this.addDefaultLanguage(
            config,
            extractStyleTag(this.content, this.html),
            'style'
        );
        this.templateInfo = this.addDefaultLanguage(
            config,
            extractTemplateTag(this.content, this.html),
            'markup'
        );
    };

    const config = configLoader.getConfig(this.getFilePath() || '');
    if (config && !config.loadConfigError) {
        update(config);
    } else {
        update(undefined);
        this.configPromise.then((c) => update(c));
    }
}

constructor(
    docManager: DocumentManager,
    configManager: LSConfigManager,
    workspaceFolders: WorkspaceFolder[],
    cssLanguageServices: CSSLanguageServices
) {
    this.cssLanguageServices = cssLanguageServices;
    this.workspaceFolders = workspaceFolders;
    this.configManager = configManager;
    this.updateConfigs();
    const workspacePaths = workspaceFolders
        .map((folder) => urlToPath(folder.uri))
        .filter(isNotNullOrUndefined);
    this.globalVars = new GlobalVars(workspacePaths);

    this.globalVars.watchFiles(this.configManager.get('css.globals'));
    this.configManager.onChange((config) => {
        this.globalVars.watchFiles(config.get('css.globals'));
        this.updateConfigs();
    });

    const sync = (document: Document) => {
        this.cssDocuments.set(document, new CSSDocument(document, this.cssLanguageServices));
    };
    docManager.on('documentChange', sync);
    docManager.on('documentOpen', sync);
    docManager.on('documentClose', (document) => this.cssDocuments.delete(document));
}

function createSvelteAnchorMissingAttributeQuickfixAction(
    textDocument: OptionalVersionedTextDocumentIdentifier,
    transpiled: ITranspiledSvelteDocument,
    content: string,
    lineOffsets: number[],
    node: Node
): CodeAction {
    // Assert non-null because the node target attribute is required for 'security-anchor-rel-noreferrer'
    const targetAttribute = node.attributes.find((i: any) => i.name == 'target')!;
    const relAttribute = node.attributes.find((i: any) => i.name == 'rel');

    const codeActionTextEdit = relAttribute
        ? TextEdit.insert(positionAt(relAttribute.end - 1, content, lineOffsets), ' noreferrer')
        : TextEdit.insert(
              positionAt(targetAttribute.end, content, lineOffsets),
              ' rel="noreferrer"'
          );

    return CodeAction.create(
        '(svelte) Add missing attribute rel="noreferrer"',
        {
            documentChanges: [
                TextDocumentEdit.create(textDocument, [
                    mapObjWithRangeToOriginal(transpiled, codeActionTextEdit)
                ])
            ]
        },
        CodeActionKind.QuickFix
    );
}

static async create(document: Document, config: SvelteConfig | undefined) {
    if (!config?.preprocess) {
        return new TranspiledSvelteDocument(document.getText());
    }

    const filename = document.getFilePath() || '';
    const preprocessed = await document.compiler.preprocess(
        document.getText(),
        wrapPreprocessors(config?.preprocess),
        {
            filename
        }
    );

    if (preprocessed.code === document.getText()) {
        return new TranspiledSvelteDocument(document.getText());
    }

    return new TranspiledSvelteDocument(
        preprocessed.code,
        preprocessed.map
            ? new SourceMapDocumentMapper(
                  createTraceMap(preprocessed.map),
                  // The "sources" array only contains the Svelte filename, not its path.
                  // For getting generated positions, the sourcemap consumer wants an exact match
                  // of the source filepath. Therefore only pass in the filename here.
                  getLastPartOfPath(filename)
              )
            : undefined
    );
}

private migrate(document: Document): WorkspaceEdit | string {
    try {
        const compiler = document.compiler as any;
        if (!compiler.migrate) {
            return 'Your installed Svelte version does not support migration';
        }

        const migrated = compiler.migrate(document.getText(), {
            filename: document.getFilePath() ?? undefined
        });

        return {
            changes: {
                [document.uri]: [
                    TextEdit.replace(
                        Range.create(
                            document.positionAt(0),
                            document.positionAt(document.getTextLength())
                        ),
                        migrated.code
                    )
                ]
            }
        };
    } catch (error: any) {
        Logger.error('Failed to migrate Svelte file', error);
        return error?.message ?? 'Failed to migrate Svelte file';
    }
}

private redirectCallHierarchyItem(
    snapshot: DocumentSnapshot,
    program: ts.Program | undefined,
    item: ts.CallHierarchyItem
): CallHierarchyItem | null {
    if (
        !isSvelteFilePath(item.file) ||
        !program ||
        !(snapshot instanceof SvelteDocumentSnapshot)
    ) {
        return null;
    }

    const sourceFile = program.getSourceFile(item.file);

    if (!sourceFile) {
        return null;
    }

    if (isGeneratedSvelteComponentName(item.name)) {
        return this.toComponentCallHierarchyItem(snapshot, item);
    }

    if (item.name === internalHelpers.renderName) {
        const end = item.selectionSpan.start + item.selectionSpan.length;
        const renderFunction = sourceFile.statements.find(
            (statement) =>
                statement.getStart() <= item.selectionSpan.start && statement.getEnd() >= end
        );

        if (!renderFunction || !sourceFile.statements.includes(renderFunction)) {
            return null;
        }
        return this.toComponentCallHierarchyItem(snapshot, item);
    }

    return null;
}

private extractImplementationLocation(
    tsDoc: SvelteDocumentSnapshot,
    item: ts.NavigationTree,
    config: TSUserConfig,
    parent?: ts.NavigationTree
): Range | undefined {
    if (
        item.kind === ts.ScriptElementKind.memberFunctionElement &&
        parent &&
        parent.kind === ts.ScriptElementKind.interfaceElement &&
        config.implementationsCodeLens?.showOnInterfaceMethods === true
    ) {
        return this.getSymbolRange(tsDoc, item);
    }
    switch (item.kind) {
        case ts.ScriptElementKind.interfaceElement:
            return this.getSymbolRange(tsDoc, item);

        case ts.ScriptElementKind.classElement:
        case ts.ScriptElementKind.memberFunctionElement:
        case ts.ScriptElementKind.memberVariableElement:
        case ts.ScriptElementKind.memberGetAccessorElement:
        case ts.ScriptElementKind.memberSetAccessorElement:
            if (item.kindModifiers.match(/\babstract\b/g)) {
                return this.getSymbolRange(tsDoc, item);
            }
            break;
    }
    return undefined;
}

async findDocumentHighlight(
    document: Document,
    position: Position
): Promise<DocumentHighlight[] | null> {
    const { tsDoc } = await this.lsAndTsDocResolver.getLsForSyntheticOperations(document);

    const svelteResult = await this.getSvelteDocumentHighlight(document, tsDoc, position);

    if (svelteResult) {
        return svelteResult;
    }

    const { lang } = await this.lsAndTsDocResolver.getLSAndTSDoc(document);

    const offset = tsDoc.offsetAt(tsDoc.getGeneratedPosition(position));
    const highlights = lang
        .getDocumentHighlights(tsDoc.filePath, offset, [tsDoc.filePath])
        ?.filter((highlight) => highlight.fileName === tsDoc.filePath);

    if (!highlights?.length) {
        return null;
    }

    const result = highlights
        .flatMap((highlight) => highlight.highlightSpans)
        .filter(this.notInGeneratedCode(tsDoc.getFullText()))
        .map((highlight) =>
            DocumentHighlight.create(
                convertToLocationRange(tsDoc, highlight.textSpan),
                this.convertHighlightKind(highlight)
            )
        )
        .filter((highlight) => !isSamePosition(highlight.range.start, highlight.range.end));

    if (!result.length) {
        return null;
    }

    return result;
}

export function getComponentAtPosition(
    lang: ts.LanguageService,
    doc: Document,
    tsDoc: SvelteDocumentSnapshot,
    originalPosition: Position
): ComponentInfoProvider | null {
    if (tsDoc.parserError) {
        return null;
    }

    if (
        isInTag(originalPosition, doc.scriptInfo) ||
        isInTag(originalPosition, doc.moduleScriptInfo)
    ) {
        // Inside script tags -> not a component
        return null;
    }

    const node = getNodeIfIsInComponentStartTag(doc.html, doc, doc.offsetAt(originalPosition));
    if (!node) {
        return null;
    }

    const symbolPosWithinNode = node.tag?.includes('.') ? node.tag.lastIndexOf('.') + 1 : 0;

    const generatedPosition = tsDoc.getGeneratedPosition(
        doc.positionAt(node.start + symbolPosWithinNode + 1)
    );

    const def = lang.getDefinitionAtPosition(
        tsDoc.filePath,
        tsDoc.offsetAt(generatedPosition)
    )?.[0];
    if (!def) {
        return null;
    }

    return JsOrTsComponentInfoProvider.create(lang, def, tsDoc.isSvelte5Plus);
}

function getCustomElementDocumentationSymbols(
    lang: ts.LanguageService,
    lsContainer: LanguageServiceContainer,
    tsDoc: SvelteDocumentSnapshot
): { type: ts.Type; typeChecker: ts.TypeChecker } | null {
    const program = lang.getProgram();
    const sourceFile = program?.getSourceFile(tsDoc.filePath);
    const typeChecker = program?.getTypeChecker();
    if (!typeChecker || !sourceFile) {
        return null;
    }

    const typingsNamespace = lsContainer.getTsConfigSvelteOptions().namespace;

    const typingsNamespaceSymbol = findTypingsNamespaceSymbol(
        typingsNamespace,
        typeChecker,
        sourceFile
    );

    if (!typingsNamespaceSymbol) {
        return null;
    }

    const elements = typeChecker
        .getExportsOfModule(typingsNamespaceSymbol)
        .find((symbol) => symbol.name === 'IntrinsicElements');

    if (!elements || !(elements.flags & ts.SymbolFlags.Interface)) {
        return null;
    }

    const type = typeChecker.getDeclaredTypeOfSymbol(elements);

    return { type, typeChecker };
}

private mapWorkspaceSymbol(
    item: ts.NavigateToItem,
    snapshot: DocumentSnapshot
): WorkspaceSymbol | undefined {
    let location = mapLocationToOriginal(snapshot, convertRange(snapshot, item.textSpan));
    if (location.range.start.line < 0) {
        if (isGeneratedSvelteComponentName(item.name)) {
            location = {
                uri: snapshot.getURL(),
                range: {
                    start: { line: 0, character: 0 },
                    end: { line: 0, character: 1 }
                }
            };
        } else {
            return undefined;
        }
    }

    return {
        kind: this.convertSymbolKindForWorkspaceSymbol(item.kind),
        name: this.getLabel(item),
        containerName:
            snapshot instanceof SvelteDocumentSnapshot &&
            (item.containerName === internalHelpers.renderName || !item.containerName)
                ? isInScript(location.range.start, snapshot)
                    ? 'script'
                    : undefined
                : item.containerName,
        location,
        tags: item.kindModifiers?.includes('deprecated') ? [SymbolTag.Deprecated] : undefined
    };
}

export function updateDiagnosticsCache(
    emitResult: EmitResult,
    caches: {
        compilerWarningsByFile?: Map<string, Diagnostic[]>;
        cssDiagnosticsByFile?: Map<string, Diagnostic[]>;
    }
) {
    const hasCompilerWarnings = !!caches.compilerWarningsByFile?.size;
    const hasCssDiagnostics = !!caches.cssDiagnosticsByFile?.size;
    if (!hasCompilerWarnings && !hasCssDiagnostics) {
        return;
    }
    const manifest = emitResult.manifest;
    if (caches.compilerWarningsByFile) {
        for (const [filePath, warnings] of caches.compilerWarningsByFile) {
            const entry = manifest.entries[filePath];
            if (entry) {
                entry.compilerWarnings = warnings;
            }
        }
    }
    if (caches.cssDiagnosticsByFile) {
        for (const [filePath, diagnostics] of caches.cssDiagnosticsByFile) {
            const entry = manifest.entries[filePath];
            if (entry) {
                entry.cssDiagnostics = diagnostics;
            }
        }
    }
    writeManifest(emitResult.manifestPath, manifest, emitResult.workspacePath);
}

function writeDiagnostics(
    workspaceUri: URI,
    writer: Writer,
    diagnostics: Array<{ filePath: string; text: string; diagnostics: Diagnostic[] }>
): Result {
    writer.start(workspaceUri.fsPath);

    const result: Result = {
        fileCount: diagnostics.length,
        errorCount: 0,
        warningCount: 0,
        fileCountWithProblems: 0
    };

    for (const diagnostic of diagnostics) {
        writer.file(
            diagnostic.diagnostics,
            workspaceUri.fsPath,
            path.relative(workspaceUri.fsPath, diagnostic.filePath),
            diagnostic.text
        );

        let fileHasProblems = false;

        diagnostic.diagnostics.forEach((d: Diagnostic) => {
            if (d.severity === DiagnosticSeverity.Error) {
                result.errorCount += 1;
                fileHasProblems = true;
            } else if (d.severity === DiagnosticSeverity.Warning) {
                result.warningCount += 1;
                fileHasProblems = true;
            }
        });

        if (fileHasProblems) {
            result.fileCountWithProblems += 1;
        }
    }

    writer.completion(
        result.fileCount,
        result.errorCount,
        result.warningCount,
        result.fileCountWithProblems
    );

    return result;
}

export async function generateResources(config: GenerateConfig) {
    workspace.fs.createDirectory(Uri.file(config.path));
    const edit = new WorkspaceEdit();

    for (const resource of config.resources) {
        const ext = resource.type === FileType.PAGE ? config.pageExtension : config.scriptExtension;
        const filepath = join(config.path, `${resource.filename}.${ext}`);

        const uri = Uri.file(filepath);
        edit.createFile(uri, {
            overwrite: false,
            ignoreIfExists: true
        });

        const data = await resource.generate(config);
        edit.insert(uri, new Position(0, 0), data);
    }

    await workspace.applyEdit(edit);

    // save documents and open the first
    await Promise.all(
        edit.entries().map(async ([uri], i) => {
            const doc = workspace.textDocuments.find((t) => t.uri.path === uri.path);
            if (doc) {
                await doc?.save();
                if (i === 0) {
                    await workspace.openTextDocument(uri);
                    await window.showTextDocument(doc);
                }
            }
        })
    );
}
